def is_safe_url(url):
    try:
        parsed = urlparse(url)
        if parsed.scheme not in ('http', 'https'):
            return False

        host = parsed.hostname
        if not host:
            return False

        # Check for IPv6 literals (e.g., [::1])
        if host.startswith('[') and host.endswith(']'):
            ip_str = host[1:-1]
